type Address struct {
	// Name is the optional human-readable display name.
	Name string
	// Address is the addr-spec, e.g. "ada@example.com".
	Address string
}

type AddressGroup struct {
	// Name is the group label shown before the colon.
	Name string
	// Addresses are the group members.
	Addresses []Address
}

type Alternative struct {
	// ContentType is the MIME media type, e.g. "text/x-web-markdown". A charset
	// parameter of utf-8 is appended automatically for text/* types that lack
	// one.
	ContentType string
	// Content is the body text.
	Content string
}

type Attachment struct {
	// Filename is the name presented to the recipient.
	Filename string
	// Content holds the raw bytes of the attachment.
	Content []byte
	// ContentType is the MIME type, e.g. "application/pdf". If empty it is
	// guessed from the filename extension, falling back to
	// "application/octet-stream".
	ContentType string
	// ContentID, when set, adds a Content-ID header so the resource can be
	// referenced from HTML via cid:ContentID. Implies an inline part.
	ContentID string
	// Inline marks the attachment as an inline part (Content-Disposition:
	// inline) rather than a regular attachment. Setting ContentID also makes
	// the part inline.
	Inline bool
}

consts.signature:
const (
	// CanonSimple is the "simple" canonicalization: header names and values are
	// used verbatim (only trailing empty body lines are stripped).
	CanonSimple Canonicalization = "simple"
	// CanonRelaxed is the "relaxed" canonicalization: header names are
	// lower-cased, whitespace runs collapsed, and body lines stripped of
	// trailing whitespace.
	CanonRelaxed Canonicalization = "relaxed"
)

