type Message struct {
	From    Address
	To      []Address
	Cc      []Address
	Bcc     []Address
	ReplyTo []Address

	// ToGroups and CcGroups hold named RFC 5322 address groups rendered in the
	// To and Cc headers respectively, in addition to the flat To/Cc slices.
	ToGroups []AddressGroup
	CcGroups []AddressGroup

	Subject string
	Text    string
	HTML    string

	// Alternatives holds additional body parts (beyond Text and HTML) to place
	// in the multipart/alternative container, such as an amp/html or watch-html
	// body. They are ordered from least to most preferred.
	Alternatives []Alternative

	// ICalEvent, when set, adds a text/calendar alternative body carrying a
	// calendar invitation.
	ICalEvent *ICalEvent

	// Headers holds additional custom headers in insertion order.
	Headers []Header

	// InReplyTo is the Message-ID (without angle brackets) this message replies
	// to. It populates the In-Reply-To header.
	InReplyTo string
	// References lists prior Message-IDs (without angle brackets) forming the
	// thread's References header.
	References []string

	// Priority sets the message priority, populating X-Priority, X-MSMail-Priority
	// and Importance headers. The zero value leaves them unset.
	Priority Priority

	// ListHeaders holds RFC 2369 / RFC 8058 List-* headers (List-Unsubscribe,
	// List-ID, ...) in insertion order.
	ListHeaders []Header

	// DKIM, when set, signs the built message with a DKIM-Signature header.
	DKIM *DKIM

	// Date is the message Date header. If zero, the current time is used at
	// Build time; set it explicitly for deterministic output.
	Date time.Time

	// MessageID is the Message-ID header without angle brackets. If empty one
	// is generated at Build time; set it explicitly for deterministic output.
	MessageID string

	// Boundary is the base MIME multipart boundary. If empty a random one is
	// generated at Build time; set it explicitly for deterministic output.
	// Nested multiparts derive their boundaries from this base.
	Boundary string

	Attachments []Attachment
	// contains filtered or unexported fields
}

type ParsedAddr struct {
	// Name is the display name (for a leaf) or the group label (for a group).
	Name string
	// Address is the addr-spec for a leaf entry; it is empty for a group.
	Address string
	// Group holds the members of a group entry; it is nil for a leaf.
	Group []ParsedAddr
	// IsGroup reports whether this entry is an RFC 5322 group. When true the
	// entry carries Group (possibly empty) instead of Address.
	IsGroup bool
}

type ParsedAttachment struct {
	// Filename is the part's filename, from Content-Disposition or Content-Type.
	Filename string
	// ContentType is the part's MIME media type without parameters.
	ContentType string
	// ContentID is the Content-ID value with any angle brackets removed.
	ContentID string
	// Inline reports whether the part had a Content-Disposition of "inline".
	Inline bool
	// Content is the fully decoded part body.
	Content []byte
}

type ParsedMessage struct {
	// Header holds the top-level message headers.
	Header mail.Header
	// From, To and Cc are the parsed address lists (empty when the header is
	// absent or unparseable).
	From []Address
	To   []Address
	Cc   []Address
	// Subject is the RFC 2047 decoded Subject header.
	Subject string
	// Date is the parsed Date header, or the zero time when absent/invalid.
	Date time.Time
	// MessageID is the Message-ID value with any angle brackets removed.
	MessageID string
	// Text is the concatenated text/plain body content, if any.
	Text string
	// HTML is the concatenated text/html body content, if any.
	HTML string
	// Attachments holds every part with an attachment or inline disposition.
	Attachments []ParsedAttachment
}

type Pool struct {
	// Transport describes how to reach the SMTP server. It is required.
	Transport *SMTPTransport
	// MaxConnections bounds the number of simultaneously open connections. It
	// defaults to 5.
	MaxConnections int
	// MaxMessages is the number of messages a single connection may carry before
	// it is closed and replaced. It defaults to 100.
	MaxMessages int
	// contains filtered or unexported fields
}

