type SMTPTransport struct {
	// Host is the SMTP server hostname.
	Host string
	// Port is the SMTP server port (e.g. 25, 465, 587).
	Port int
	// Username and Password enable PLAIN authentication when Username is set
	// and Auth is nil.
	Username string
	Password string
	// Auth overrides the default PLAIN authentication mechanism.
	Auth smtp.Auth
	// TLS uses implicit TLS for the whole connection (typically port 465).
	TLS bool
	// STARTTLS upgrades a plaintext connection to TLS (typically port 587).
	STARTTLS bool
	// TLSConfig is the TLS configuration used for TLS/STARTTLS. When nil a
	// config with ServerName set to Host is used.
	TLSConfig *tls.Config
	// LocalName is the name sent in the EHLO/HELO command.
	LocalName string
	// DSN, when set, requests RFC 3461 delivery status notifications by adding
	// parameters to the MAIL FROM and RCPT TO commands.
	DSN *DSNOptions
	// contains filtered or unexported fields
}

type SendmailTransport struct {
	// Path is the sendmail binary to run. It defaults to "/usr/sbin/sendmail".
	Path string
	// Args are extra arguments inserted before the computed envelope arguments.
	Args []string
	// UseHeaders passes -t so sendmail extracts recipients from the message
	// headers instead of the command line. When false the envelope sender (-f)
	// and the recipient addresses are passed explicitly.
	UseHeaders bool
}

type Service struct {
	// Name is the canonical provider name, e.g. "Gmail".
	Name string
	// Host is the SMTP submission host, e.g. "smtp.gmail.com".
	Host string
	// Port is the SMTP submission port, e.g. 465 or 587.
	Port int
	// Secure reports whether the connection uses implicit TLS from the start
	// (typically port 465). When false, callers should use STARTTLS on the
	// submission port (typically 587).
	Secure bool
}

type StreamTransport struct {
	// Writer receives the raw bytes of every sent message. It must be non-nil.
	Writer io.Writer
	// contains filtered or unexported fields
}

type Transport interface {
	Send(from string, to []string, raw []byte) error
}

type Transporter struct {
	Transport Transport
}

